import { v4 } from 'uuid'
import createPersistedState from 'use-persisted-state';
import { getClock } from './clock';
import Timestamp from './timestamp';
import { applyMessages, onSync, sendMessages, sync } from './sync';
import {useEffect, useState} from 'react';

let data = {}
let messages = []

function insert(table: string, row: any) {
  let id = v4();
  let fields = Object.keys(row);

  sendMessages(
    fields.map(k => {
      return {
        dataset: table,
        row: row.id || id,
        column: k,
        value: row[k],
        timestamp: Timestamp.send(getClock()).toString()
      };
    })
  );

  return id;
}

function getAll(table: string) {
  if (!data[table]) data[table] = []
  return data[table].filter(row => row.tombstone !== 1);
}

function getData() {
  return data
}

function setData(newData) {
  data = newData
}

function getMessages() {
  return messages
}

function createUseDb(key: string) {
  const persistedState = createPersistedState(key);
  return function useDb(table: string) {
    const [msgs, setMsgs] = persistedState(getMessages() || [])
    const [dat, setDat] = useState([])
    // onSync(() => setMsgs([...getMessages()]))
    useEffect(() => {
      console.log('data antes de aplicar msgs: ', data)
      applyMessages(msgs)
      console.log('data DEPOIS de aplicar msgs: ', data)
      setDat(data[table])
    }, [msgs])

    async function syncR() {
      await sync()
      setMsgs([...getMessages()])
    }

    return [dat || [], function insertData(row) {
      insert(table, row)
      const mes = getMessages()
      console.log('msgs depois do insert: ', mes)
      console.log('tamanho: ', mes.length)
      setMsgs([...getMessages()])
    }, syncR]
  }

}

export {
  createUseDb,
  getAll,
  getData,
  setData,
  getMessages,
  insert,
}
